return $input.all().map(item => {

  const data = item.json;

  const mapaMotoqueiros = {
    1: "AMANDA",
    2: "FRANCISCO",
    3: "JEOVA",
    4: "RICARDO",
    5: "SANDRO",
    6: "OUTROS",
    7: "CKELY",
    8: "PRISCILA"
  };

  const idMotoqueiro = Number(data.MOTOQUEIROS);
  const nomeMotoqueiro = mapaMotoqueiros[idMotoqueiro] || "";

  return {
    json: {
      ...data,
      nomeMotoqueiro
    }
  };
});

